import{_ as a,o as s,c as o,ai as t}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"远程控制","description":"","frontmatter":{"read_when":["设置或调试远程 mac 控制时"],"summary":"macOS 应用通过 SSH 控制远程 OpenSoul Gateway 网关的流程","title":"远程控制","x-i18n":{"generated_at":"2026-02-03T07:52:53Z","model":"claude-opus-4-5","provider":"pi","source_hash":"61b43707250d5515fd0f85f092bdde24598f14904398ff3fca3736bcc48d72f8","source_path":"platforms/mac/remote.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/remote.md","filePath":"zh-CN/platforms/mac/remote.md","lastUpdated":1771906665000}'),i={name:"zh-CN/platforms/mac/remote.md"};function l(n,e,r,d,c,h){return s(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="远程-opensoul-macos-⇄-远程主机" tabindex="-1"><a class="header-anchor" href="#远程-opensoul-macos-⇄-远程主机">#</a> 远程 OpenSoul（macOS ⇄ 远程主机）</h1><p>此流程让 macOS 应用作为运行在另一台主机（桌面/服务器）上的 OpenSoul Gateway 网关的完整远程控制。这是应用的 <strong>Remote over SSH</strong>（远程运行）功能。所有功能——健康检查、语音唤醒转发和 Web Chat——都重用来自 <em>Settings → General</em> 的相同远程 SSH 配置。</p><h2 id="模式" tabindex="-1"><a class="header-anchor" href="#模式">#</a> 模式</h2><ul><li><strong>Local (this Mac)</strong>：一切都在笔记本电脑上运行。不涉及 SSH。</li><li><strong>Remote over SSH（默认）</strong>：OpenSoul 命令在远程主机上执行。mac 应用使用 <code>-o BatchMode</code> 加上你选择的身份/密钥打开 SSH 连接，并进行本地端口转发。</li><li><strong>Remote direct (ws/wss)</strong>：无 SSH 隧道。mac 应用直接连接到 Gateway 网关 URL（例如，通过 Tailscale Serve 或公共 HTTPS 反向代理）。</li></ul><h2 id="远程传输" tabindex="-1"><a class="header-anchor" href="#远程传输">#</a> 远程传输</h2><p>远程模式支持两种传输方式：</p><ul><li><strong>SSH 隧道</strong>（默认）：使用 <code>ssh -N -L ...</code> 将 Gateway 网关端口转发到 localhost。Gateway 网关会将节点的 IP 视为 <code>127.0.0.1</code>，因为隧道是 loopback。</li><li><strong>Direct (ws/wss)</strong>：直接连接到 Gateway 网关 URL。Gateway 网关看到真实的客户端 IP。</li></ul><h2 id="远程主机上的先决条件" tabindex="-1"><a class="header-anchor" href="#远程主机上的先决条件">#</a> 远程主机上的先决条件</h2><ol><li>安装 Node + pnpm 并构建/安装 OpenSoul CLI（<code>pnpm install &amp;&amp; pnpm build &amp;&amp; pnpm link --global</code>）。</li><li>确保 <code>opensoul</code> 在非交互式 shell 的 PATH 中（如需要，请符号链接到 <code>/usr/local/bin</code> 或 <code>/opt/homebrew/bin</code>）。</li><li>使用密钥认证打开 SSH。我们推荐使用 <strong>Tailscale</strong> IP 以实现离开局域网时的稳定可达性。</li></ol><h2 id="macos-应用设置" tabindex="-1"><a class="header-anchor" href="#macos-应用设置">#</a> macOS 应用设置</h2><ol><li>打开 <em>Settings → General</em>。</li><li>在 <strong>OpenSoul runs</strong> 下，选择 <strong>Remote over SSH</strong> 并设置： <ul><li><strong>Transport</strong>：<strong>SSH tunnel</strong> 或 <strong>Direct (ws/wss)</strong>。</li><li><strong>SSH target</strong>：<code>user@host</code>（可选 <code>:port</code>）。 <ul><li>如果 Gateway 网关在同一局域网上并广播 Bonjour，从发现列表中选择它以自动填充此字段。</li></ul></li><li><strong>Gateway URL</strong>（仅 Direct）：<code>wss://gateway.example.ts.net</code>（或本地/局域网使用 <code>ws://...</code>）。</li><li><strong>Identity file</strong>（高级）：你的密钥路径。</li><li><strong>Project root</strong>（高级）：用于命令的远程 checkout 路径。</li><li><strong>CLI path</strong>（高级）：可运行的 <code>opensoul</code> 入口点/二进制文件的可选路径（广播时自动填充）。</li></ul></li><li>点击 <strong>Test remote</strong>。成功表示远程 <code>opensoul status --json</code> 正确运行。失败通常意味着 PATH/CLI 问题；退出码 127 表示远程找不到 CLI。</li><li>健康检查和 Web Chat 现在将自动通过此 SSH 隧道运行。</li></ol><h2 id="web-chat" tabindex="-1"><a class="header-anchor" href="#web-chat">#</a> Web Chat</h2><ul><li><strong>SSH 隧道</strong>：Web Chat 通过转发的 WebSocket 控制端口（默认 18789）连接到 Gateway 网关。</li><li><strong>Direct (ws/wss)</strong>：Web Chat 直接连接到配置的 Gateway 网关 URL。</li><li>不再有单独的 WebChat HTTP 服务器。</li></ul><h2 id="权限" tabindex="-1"><a class="header-anchor" href="#权限">#</a> 权限</h2><ul><li>远程主机需要与本地相同的 TCC 批准（自动化、辅助功能、屏幕录制、麦克风、语音识别、通知）。在该机器上运行新手引导以一次性授予它们。</li><li>节点通过 <code>node.list</code> / <code>node.describe</code> 广播其权限状态，以便智能体知道哪些可用。</li></ul><h2 id="安全注意事项" tabindex="-1"><a class="header-anchor" href="#安全注意事项">#</a> 安全注意事项</h2><ul><li>优先在远程主机上使用 loopback 绑定，并通过 SSH 或 Tailscale 连接。</li><li>如果你将 Gateway 网关绑定到非 loopback 接口，请要求令牌/密码认证。</li><li>参见<a href="/docs/gateway/security/index">安全</a>和 <a href="/docs/gateway/tailscale">Tailscale</a>。</li></ul><h2 id="whatsapp-登录流程-远程" tabindex="-1"><a class="header-anchor" href="#whatsapp-登录流程-远程">#</a> WhatsApp 登录流程（远程）</h2><ul><li><strong>在远程主机上</strong>运行 <code>opensoul channels login --verbose</code>。用手机上的 WhatsApp 扫描二维码。</li><li>如果认证过期，在该主机上重新运行登录。健康检查会显示关联问题。</li></ul><h2 id="故障排除" tabindex="-1"><a class="header-anchor" href="#故障排除">#</a> 故障排除</h2><ul><li><strong>exit 127 / not found</strong>：<code>opensoul</code> 不在非登录 shell 的 PATH 中。将其添加到 <code>/etc/paths</code>、你的 shell rc，或符号链接到 <code>/usr/local/bin</code>/<code>/opt/homebrew/bin</code>。</li><li><strong>Health probe failed</strong>：检查 SSH 可达性、PATH，以及 Baileys 是否已登录（<code>opensoul status --json</code>）。</li><li><strong>Web Chat 卡住</strong>：确认 Gateway 网关正在远程主机上运行，转发的端口与 Gateway 网关 WS 端口匹配；UI 需要健康的 WS 连接。</li><li><strong>节点 IP 显示 127.0.0.1</strong>：使用 SSH 隧道时是预期的。如果你想让 Gateway 网关看到真实的客户端 IP，请将 <strong>Transport</strong> 切换到 <strong>Direct (ws/wss)</strong>。</li><li><strong>Voice Wake</strong>：触发短语在远程模式下自动转发；不需要单独的转发器。</li></ul><h2 id="通知声音" tabindex="-1"><a class="header-anchor" href="#通知声音">#</a> 通知声音</h2><p>通过带有 <code>opensoul</code> 和 <code>node.invoke</code> 的脚本为每个通知选择声音，例如：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> notify</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --title</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Ping&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --body</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Remote gateway ready&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sound</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Glass</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>应用中不再有全局&quot;默认声音&quot;开关；调用者为每个请求选择声音（或无声音）。</p>',25)])])}const u=a(i,[["render",l]]);export{g as __pageData,u as default};
